    let mut low = 0;
    let mut high = arr.len().saturating_sub(1);

    while low <= high {
        let mid = low + (high - low) / 2;
        let val = arr[mid];

        if val == target {
            return Some(mid);
        } else if val < target {
            low = mid + 1;
