impl<T> RawVec<T> {
    pub fn push(&mut self, value: T) {
        if self.len < self.cap {
            unsafe {
                ptr::write(self.ptr.add(self.len), value);
                self.len += 1;
            }
        } else {
            let new_cap = if self.cap == 0 { 1 } else { self.cap * 2 };
            let layout = Layout::array::<T>(new_cap).expect("overflow of capacity");
            let new_ptr = if self.cap == 0 {
                alloc(layout)
            } else {
                realloc(self.ptr, Layout::array::<T>(self.cap).unwrap(), new_cap)
            };

            unsafe {
                ptr::copy_nonoverlapping(self.ptr, new_ptr, self.len);
                ptr::write(new_ptr.add(self.len), value);
                if self.cap != 0 {
                    dealloc(self.ptr, Layout::array::<T>(self.cap).unwrap());
                }
                self.ptr = new_ptr;
                self.cap = new_cap;
                self.len += 1;
            }
        }
    }
}

