pub fn rotate_right<T: Clone>(arr: &mut [T], k: usize) {
    let n = arr.len();
    if n == 0 {
        return;
    }
    k = k % n;
    if k == 0 {
        return;
    }

    // Helper closure to reverse a slice in place
    let mut reverse = |start: usize, end: usize| {
        let mut i = start;
        let mut j = end - 1;
        while i < j {
            arr.swap(i, j);
            i += 1;
            j -= 1;
        }
    };

    reverse(0, n);
    reverse(0, k);
    reverse(k, n);
}

