pub fn longest_common_prefix(strs: &[&str]) -> String {
    if strs.is_empty() {
        return String::new();
    }

    // Vertical scanning
    let first = strs[0];
    for (i, c) in first.chars().enumerate() {
        for s in strs.iter().skip(1) {
            if i >= s.len() || s.chars().nth(i) != Some(c) {
                return first[..i].to_string();
            }
        }
    }
    first.to_string()
}

