}

use std::sync::atomic::AtomicUsize;
use std::thread;

pub fn parallel_increment(counter: &AtomicUsize, threads: usize, per_thread: usize) -> usize {
    let mut handles = vec![];

    for _ in 0..threads {
        let handle = thread::spawn(move || {
            for _ in 0..per_thread {
                counter.fetch_add(1, Ordering::SeqCst);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    counter.load(Ordering::SeqCst)
}

